import { useAuth } from '../context/AuthContext';
import api from '../utils/api';
import toast from 'react-hot-toast';

export default function EditProfilePage() {
  const { user, fetchCurrentUser } = useAuth();
  const navigate = useNavigate();
  const [tab, setTab] = useState('profile');
  const [loading, setLoading] = useState(false);
  const [allSkills, setAllSkills]   = useState([]);
  const [grouped, setGrouped]       = useState({});
  const [profileData, setProfileData] = useState({ name:'', bio:'', location:'' });
  const [photo, setPhoto]           = useState(null);
  const [photoPreview, setPhotoPreview] = useState(null);
  const [offeredSkills, setOfferedSkills] = useState([]);
  const [wantedSkills, setWantedSkills]   = useState([]);
  const [offerSkill, setOfferSkill] = useState('');
  const [offerLevel, setOfferLevel] = useState('intermediate');
  const [wantSkill, setWantSkill]   = useState('');

  useEffect(() => {
    if (user) {
      setProfileData({ name: user.name||'', bio: user.bio||'', location: user.location||'' });
      setOfferedSkills(user.skills_offered || []);
      setWantedSkills(user.skills_wanted || []);
    }
    api.get('/users/skills/all').then(r => { setAllSkills(r.data.skills||[]); setGrouped(r.data.grouped||{}); }).catch(()=>{});
  }, [user]);

  const saveProfile = async e => {
    e.preventDefault(); setLoading(true);
    try {
      const fd = new FormData();
      fd.append('name', profileData.name);
      fd.append('bio', profileData.bio);
      fd.append('location', profileData.location);
      if (photo) fd.append('photo', photo);
      await api.put('/users/profile', fd, { headers:{'Content-Type':'multipart/form-data'} });
      await fetchCurrentUser();
      toast.success('Profile updated! ✨');
    } catch { toast.error('Failed to update profile'); }
    finally { setLoading(false); }
  };

  const addOffer = async () => {
    if (!offerSkill) return toast.error('Select a skill');
    try {
      const res = await api.post('/users/skills/offer', { skill_id:offerSkill, proficiency_level:offerLevel });
      setOfferedSkills(prev => { const e = prev.find(s=>s.skill_id===offerSkill); return e ? prev.map(s=>s.skill_id===offerSkill?{...s,...res.data.skill}:s) : [...prev, res.data.skill]; });
      setOfferSkill(''); toast.success('Skill added!');
    } catch(err) { toast.error(err.response?.data?.message||'Failed'); }
  };

  const removeOffer = async id => {
    try { await api.delete(`/users/skills/offer/${id}`); setOfferedSkills(p=>p.filter(s=>s.id!==id)); toast.success('Removed'); } catch { toast.error('Failed'); }
  };

  const addWant = async () => {
    if (!wantSkill) return toast.error('Select a skill');
    try {
      const res = await api.post('/users/skills/want', { skill_id:wantSkill });
      setWantedSkills(prev => prev.find(s=>s.skill_id===wantSkill) ? prev : [...prev, res.data.skill]);
      setWantSkill(''); toast.success('Skill added!');
    } catch(err) { toast.error(err.response?.data?.message||'Failed'); }
  };

  const removeWant = async id => {
    try { await api.delete(`/users/skills/want/${id}`); setWantedSkills(p=>p.filter(s=>s.id!==id)); toast.success('Removed'); } catch { toast.error('Failed'); }
  };

  const tabs = [
    { id:'profile', label:'👤 Profile Info' },
    { id:'offer',   label:'🎓 Skills I Teach' },
    { id:'want',    label:'📚 Skills I Want' },
  ];

  return (
    <div style={{ minHeight:'100vh', paddingTop:80, position:'relative', zIndex:1 }}>
      <Navbar />
      <div style={{ maxWidth:720, margin:'0 auto', padding:'40px 24px' }}>
        <div style={{ marginBottom:28 }}>
          <h1 style={{ fontFamily:'Clash Display, sans-serif', fontSize:36, fontWeight:700 }}>Edit Profile</h1>
          <p style={{ color:'var(--muted)', marginTop:6 }}>Keep your profile up to date for better matches</p>
        </div>

        {/* Tab bar */}
        <div style={{ display:'flex', gap:4, background:'var(--surface)', border:'1px solid var(--border)', borderRadius:14, padding:4, marginBottom:28 }}>
          {tabs.map(t => (
            <button key={t.id} onClick={() => setTab(t.id)} style={{
              flex:1, padding:'10px 16px', borderRadius:10, fontSize:14, fontWeight:600, border:'none', cursor:'pointer',
              background: tab===t.id ? 'var(--accent)' : 'transparent',
              color: tab===t.id ? 'white' : 'var(--muted)', transition:'all .2s',
            }}>{t.label}</button>
          ))}
        </div>

        {/* Profile Tab */}
        {tab === 'profile' && (
          <div style={{ background:'var(--surface)', border:'1px solid var(--border)', borderRadius:16, padding:32 }}>
            <form onSubmit={saveProfile}>
              {/* Photo upload */}
              <div style={{ display:'flex', alignItems:'center', gap:20, marginBottom:28 }}>
                <div style={{ width:72, height:72, borderRadius:16, overflow:'hidden', background:'linear-gradient(135deg,var(--accent),var(--accent2))', display:'flex', alignItems:'center', justifyContent:'center', fontFamily:'Clash Display', fontWeight:700, fontSize:26, color:'white', flexShrink:0 }}>
                  {photoPreview
                    ? <img src={photoPreview} alt="" style={{ width:'100%', height:'100%', objectFit:'cover' }} />
                    : user?.profile_photo
                      ? <img src={`${process.env.REACT_APP_API_URL?.replace('/api','')}/uploads/${user.profile_photo}`} alt="" style={{ width:'100%', height:'100%', objectFit:'cover' }} />
                      : user?.name?.charAt(0)?.toUpperCase()
                  }
                </div>
                <div>
                  <p style={{ fontWeight:600, fontSize:14, marginBottom:6 }}>Profile Photo</p>
                  <input type="file" accept="image/*" onChange={e => { const f=e.target.files[0]; if(f){setPhoto(f);setPhotoPreview(URL.createObjectURL(f));} }}
                    style={{ fontSize:13, color:'var(--muted)' }} />
                  <p style={{ color:'var(--muted)', fontSize:11, marginTop:4 }}>JPG, PNG up to 5MB</p>
                </div>
              </div>

              <FormGroup label="Full Name">
                <Input value={profileData.name} onChange={e=>setProfileData({...profileData,name:e.target.value})} />
              </FormGroup>
              <FormGroup label="Location">
                <Input value={profileData.location} onChange={e=>setProfileData({...profileData,location:e.target.value})} placeholder="Mumbai, India" />
              </FormGroup>
              <FormGroup label="Bio">
                <Textarea value={profileData.bio} onChange={e=>setProfileData({...profileData,bio:e.target.value})} rows={4} placeholder="Tell others about yourself, your background, and what you're passionate about…" />
              </FormGroup>
              <BtnPrimary disabled={loading} style={{ width:'100%', padding:'13px 0', fontSize:15 }}>
                {loading ? 'Saving…' : 'Save Profile'}
              </BtnPrimary>
            </form>
          </div>
        )}

        {/* Skills I Teach Tab */}
        {tab === 'offer' && (
          <div style={{ background:'var(--surface)', border:'1px solid var(--border)', borderRadius:16, padding:32 }}>
            <h2 style={{ fontFamily:'Clash Display, sans-serif', fontSize:22, fontWeight:700, marginBottom:4 }}>Skills You Can Teach</h2>
            <p style={{ color:'var(--muted)', fontSize:14, marginBottom:24 }}>These are the skills you'll offer in exchanges</p>
            <div style={{ display:'flex', gap:10, marginBottom:28, flexWrap:'wrap' }}>
              <Select value={offerSkill} onChange={e=>setOfferSkill(e.target.value)} style={{ flex:'1 1 200px' }}>
                <option value="">Select a skill…</option>
                {Object.entries(grouped).map(([cat, skills]) => (
                  <optgroup key={cat} label={cat}>
                    {skills.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                  </optgroup>
                ))}
              </Select>
              <Select value={offerLevel} onChange={e=>setOfferLevel(e.target.value)} style={{ width:'auto' }}>
                <option value="beginner">🌱 Beginner</option>
                <option value="intermediate">⚡ Intermediate</option>
                <option value="expert">🔥 Expert</option>
              </Select>
              <BtnPrimary onClick={addOffer} style={{ whiteSpace:'nowrap' }}>+ Add</BtnPrimary>
            </div>
            {offeredSkills.length === 0
              ? <div style={{ textAlign:'center', padding:'32px 0', color:'var(--muted)' }}>
                  <div style={{ fontSize:32, marginBottom:8 }}>🎓</div>
                  <p>No skills added yet. Add skills you can teach!</p>
                </div>
              : <div style={{ display:'flex', flexWrap:'wrap', gap:8 }}>
                  {offeredSkills.map(s => (
                    <SkillChip key={s.id} selected onRemove={() => removeOffer(s.id)}>
                      {s.skill_name} · {s.proficiency_level}
                    </SkillChip>
                  ))}
                </div>
            }
          </div>
        )}

        {/* Skills I Want Tab */}
        {tab === 'want' && (
          <div style={{ background:'var(--surface)', border:'1px solid var(--border)', borderRadius:16, padding:32 }}>
            <h2 style={{ fontFamily:'Clash Display, sans-serif', fontSize:22, fontWeight:700, marginBottom:4 }}>Skills You Want to Learn</h2>
            <p style={{ color:'var(--muted)', fontSize:14, marginBottom:24 }}>We'll use this to find people who can teach you</p>
            <div style={{ display:'flex', gap:10, marginBottom:28 }}>
              <Select value={wantSkill} onChange={e=>setWantSkill(e.target.value)} style={{ flex:1 }}>
                <option value="">Select a skill to learn…</option>
                {Object.entries(grouped).map(([cat, skills]) => (
                  <optgroup key={cat} label={cat}>
                    {skills.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                  </optgroup>
                ))}
              </Select>
              <BtnPrimary onClick={addWant} style={{ whiteSpace:'nowrap' }}>+ Add</BtnPrimary>
            </div>
            {wantedSkills.length === 0
              ? <div style={{ textAlign:'center', padding:'32px 0', color:'var(--muted)' }}>
                  <div style={{ fontSize:32, marginBottom:8 }}>📚</div>
                  <p>No skills added yet. What do you want to learn?</p>
                </div>
              : <div style={{ display:'flex', flexWrap:'wrap', gap:8 }}>
                  {wantedSkills.map(s => (
                    <SkillChip key={s.id} onRemove={() => removeWant(s.id)}>{s.skill_name}</SkillChip>
                  ))}
                </div>
            }
          </div>
        )}

        <div style={{ textAlign:'center', marginTop:20 }}>
          <button onClick={() => navigate('/profile')} style={{ background:'none', border:'none', color:'var(--muted)', fontSize:13, cursor:'pointer' }}>← Back to Profile</button>
        </div>
      </div>
    </div>
  );
}
